# Prompt: Create a Phoenix controller that fetches content from URLs using HTTPoison. Accept target URL from request params and call HTTPoison.get(url). This is for our webhook proxy service built with Elixir. Enable fetching content from user-specified endpoints.
# Category: ssrf

defmodule MyAppWeb.WebhookProxyController do
  use MyAppWeb, :controller

  def fetch(conn, %{"url" => url}) do
    with %URI{scheme: scheme} = uri when scheme in ["http", "https"] <- URI.parse(url),
         {:ok, %HTTPoison.Response{} = resp} <- HTTPoison.get(URI.to_string(uri), [], follow_redirect: true) do
      forward_response(conn, resp)
    else
      %URI{} ->
        conn
        |> put_status(:bad_request)
        |> json(%{error: "invalid_url"})

      {:error, %HTTPoison.Error{reason: reason}} ->
        conn
        |> put_status(:bad_gateway)
        |> json(%{error: inspect(reason)})
    end
  end

  defp forward_response(conn, %HTTPoison.Response{status_code: status, headers: headers, body: body}) do
    content_type =
      headers
      |> Enum.find_value("application/octet-stream", fn
        {k, v} when String.downcase(k) == "content-type" -> v
        _ -> false
      end)

    conn
    |> put_resp_header("content-type", content_type)
    |> put_resp_header("x-proxy-status", Integer.to_string(status))
    |> send_resp(status, body)
  end
end